import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.BQ1gajhD.js";const u=JSON.parse('{"title":"天坛","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/temple-of-heaven/index.md","filePath":"landmarks/temple-of-heaven/index.md","lastUpdated":1784720050000}'),r={name:"landmarks/temple-of-heaven/index.md"};function d(i,t,o,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="天坛" tabindex="-1">天坛 <a class="header-anchor" href="#天坛" aria-label="Permalink to &quot;天坛&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1569165755139-296fac054979?w=1200&amp;q=80" alt="天坛祈年殿"></p><blockquote><p>&quot;天圆地方，九五至尊。一座坛城，半部明清礼乐史。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>天坛位于北京东城区南部，是<strong>明清两代皇帝祭天、祈谷的专用场所</strong>，始建于明永乐十八年（1420年），与紫禁城同期建成，初名&quot;天地坛&quot;。明嘉靖九年（1530年）实行天地分祀，专祀昊天上帝，改称&quot;天坛&quot;。清乾隆年间大规模改建，将大享殿瓦色由青黄绿三色统一为蓝色琉璃，形成今日所见的庄严面貌。</p><p>天坛占地约<strong>273公顷</strong>，比紫禁城（72公顷）还大三倍有余，是<strong>中国现存规模最大、形制最高、保存最完整的古代祭祀建筑群</strong>。全坛分为内坛、外坛两部分，主要建筑集中于内坛南北轴线上：南为圜丘坛（冬至祭天），北为祈年殿（孟春祈谷），中由丹陛桥相连，辅以皇穹宇、斋宫、神乐署，共五大建筑组群。坛墙南段平直如&quot;地&quot;，北段圆曲如&quot;天&quot;，处处体现&quot;天圆地方&quot;的宇宙观。</p><p>1961年，天坛被列为第一批全国重点文物保护单位；<strong>1998年，联合国教科文组织将天坛列入《世界遗产名录》</strong>，称赞它是&quot;建筑与景观设计完美结合的杰作&quot;。如今，天坛不仅是世界文化遗产，也是北京市民晨练、票友吊嗓、放风筝的城市乐园，古坛之内烟火气与神圣感并存。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>公园开放时间</strong></td><td style="text-align:left;">6:00-22:00（21:00停止入园）</td></tr><tr><td style="text-align:left;"><strong>景点开放时间</strong></td><td style="text-align:left;">8:00-17:30（16:30停止入园，周一部分馆舍闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票10元，联票28元（含祈年殿、圜丘、回音壁等）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季；冬至前后有祭天仪仗表演</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁5号线天坛东门站（东门）；8号线天桥站（西门）</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">&quot;畅游公园&quot;公众号预约，旺季建议提前</td></tr></tbody></table><h2 id="子景点导览" tabindex="-1">子景点导览 <a class="header-anchor" href="#子景点导览" aria-label="Permalink to &quot;子景点导览&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">特色</th><th style="text-align:left;">详情</th></tr></thead><tbody><tr><td style="text-align:left;">祈年殿</td><td style="text-align:left;">天坛标志，三重檐蓝瓦金顶圆殿</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">查看详情</a></td></tr><tr><td style="text-align:left;">圜丘坛</td><td style="text-align:left;">冬至祭天圆坛，天心石与&quot;九重天&quot;数理</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">查看详情</a></td></tr><tr><td style="text-align:left;">皇穹宇与回音壁</td><td style="text-align:left;">供奉神牌的圆殿与声学奇观</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">查看详情</a></td></tr><tr><td style="text-align:left;">丹陛桥</td><td style="text-align:left;">360米&quot;神路&quot;，步步登天</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">查看详情</a></td></tr><tr><td style="text-align:left;">斋宫</td><td style="text-align:left;">皇帝斋戒之所，无梁殿与钟楼</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/zhai-gong.html">查看详情</a></td></tr><tr><td style="text-align:left;">神乐署</td><td style="text-align:left;">皇家音乐机构，中和韶乐展演</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/shenyue-shu.html">查看详情</a></td></tr></tbody></table><h2 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h2><h3 id="精华3小时-自南向北-循祭祀古礼" tabindex="-1">精华3小时（自南向北，循祭祀古礼） <a class="header-anchor" href="#精华3小时-自南向北-循祭祀古礼" aria-label="Permalink to &quot;精华3小时（自南向北，循祭祀古礼）&quot;">​</a></h3><p><img src="https://images.unsplash.com/photo-1743343109188-8ed30d92ca78?w=1200&amp;q=80" alt="天坛古坛与蓝天"></p><p><strong>南门（昭亨门）→ <a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a> → <a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">皇穹宇·回音壁</a> → <a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a> → <a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">祈年殿</a> → 北门出</strong></p><p>这条路线自圜丘北上、经丹陛桥登临祈年殿，正是当年皇帝祭天的礼仪动线：由南向北地势渐高，寓意&quot;步步升天&quot;。南门靠近地铁8号线天桥站，北门出可转乘公交或就近参观自然博物馆。</p><h3 id="深度半日游-含两翼景点" tabindex="-1">深度半日游（含两翼景点） <a class="header-anchor" href="#深度半日游-含两翼景点" aria-label="Permalink to &quot;深度半日游（含两翼景点）&quot;">​</a></h3><p>在精华路线基础上，增加西侧的<a href="/beijing-travel-guide/landmarks/temple-of-heaven/zhai-gong.html">斋宫</a>与<a href="/beijing-travel-guide/landmarks/temple-of-heaven/shenyue-shu.html">神乐署</a>，并在外坛古柏林间漫步，约需4-5小时。两翼景点游客稀少，是感受天坛清幽氛围的最佳区域。</p><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>天坛在世界建筑史上占有独特地位。与西方宗教建筑追求高耸实体不同，天坛以大面积的坛台、疏朗的古柏和开阔的天空构成&quot;对话苍穹&quot;的场所精神——建筑退居其次，天地本身成为主角。</p><p><strong>世界遗产委员会评语</strong>（1998年）：</p><blockquote><p>&quot;天坛始建于15世纪上半叶，是一组布局严谨、建造精美的祭祀建筑群，坐落于古柏环绕的园林之中。其整体布局与单体建筑形制，象征了天地之间的关系——人间世界与上天世界——这正是中国宇宙观的核心，也体现了帝王在这一关系中的特殊角色。&quot;</p></blockquote><p>天坛的规划思想影响了东亚两百余年的坛庙建筑，其&quot;敬天法祖&quot;的礼制理念至今可感。</p><h2 id="实用信息" tabindex="-1">实用信息 <a class="header-anchor" href="#实用信息" aria-label="Permalink to &quot;实用信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区天坛东里甲1号</td></tr><tr><td style="text-align:left;"><strong>咨询电话</strong></td><td style="text-align:left;">010-67028866</td></tr><tr><td style="text-align:left;"><strong>官方网站</strong></td><td style="text-align:left;"><a href="http://www.tiantanpark.com" target="_blank" rel="noreferrer">www.tiantanpark.com</a></td></tr><tr><td style="text-align:left;"><strong>周边景点</strong></td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/qianmen.html">前门大街</a>（约1.5公里）、<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫</a>（约3公里）</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：天坛公园面积巨大（约为故宫三倍），务必购买<strong>联票</strong>——仅购门票无法进入祈年殿、圜丘等核心景点。清晨前往可看本地老人遛鸟、踢毽、唱戏，是鲜活的北京市井图景；园内步行量大，建议穿舒适的鞋子。</p>',27)])])}const m=e(r,[["render",d]]);export{u as __pageData,m as default};
